using System;

class Program {
    static void Main() {
        int? age = null;
        Console.WriteLine(age.HasValue);
        age = 30;
        Console.WriteLine(age.HasValue);
        Console.WriteLine(age.Value);
    }
}

using System;

class Program {
    static void Main() {
        int? a = null;
        int? b = 42;
        Console.WriteLine(a ?? 0);
        Console.WriteLine(b ?? 0);
        string s = null;
        Console.WriteLine(s ?? "default");
    }
}

using System;

class Program {
    static void Main() {
        string s = null;
        int? len = s?.Length;
        Console.WriteLine(len);
        Console.WriteLine(len ?? -1);

        string hello = "hello";
        Console.WriteLine(hello?.ToUpper());
    }
}

using System;

class Program {
    static void Main() {
        string s = null;
        s ??= "default";
        Console.WriteLine(s);

        string t = "existing";
        t ??= "not used";
        Console.WriteLine(t);
    }
}

using System;

#nullable enable

class Program {
    static string Greet(string? name) {
        return $"Hello, {name ?? "stranger"}!";
    }

    static void Main() {
        Console.WriteLine(Greet("Alice"));
        Console.WriteLine(Greet(null));
    }
}

using System;

#nullable enable

class Program {
    static string? TryGetName() => "Alice";

    static void Main() {
        string name = TryGetName()!; // I know it won't be null
        Console.WriteLine(name.Length);
    }
}

using System;

static string Describe(object obj) {
    if (obj is null) return "null";
    if (obj is string s) return $"string: \"{s}\"";
    if (obj is int n) return $"int: {n}";
    return $"other: {obj.GetType().Name}";
}

class Program {
    static void Main() {
        Console.WriteLine(Describe(null));
        Console.WriteLine(Describe("hello"));
        Console.WriteLine(Describe(42));
        Console.WriteLine(Describe(3.14));
    }
}

using System;
using System.Linq;
using System.Collections.Generic;

class Program {
    static void Main() {
        var names = new List<string?> { "Alice", null, "Bob", null, "Carol" };
        var nonNull = names.Where(n => n != null).ToList();
        Console.WriteLine(nonNull.Count);
        Console.WriteLine(string.Join(", ", nonNull));
    }
}
